If you get an error when creating the stage. <p>Just wait 30 seconds to a minute and try again. Sometimes it takes Azure a bit to update security.</p> <p>Lets setup the stage, file format, warehouse and finally load some json data.</p>  Template Example Result <p><pre><code>use database raw;
use schema azure;
use role sysadmin;
use warehouse development;

/*
   Stages are synonymous with the idea of folders
   that can be either internal or external.
*/
create or replace stage azure
storage_integration = azure_integration
url = 'azure://&lt;STORAGE NAME&gt;.blob.core.windows.net/&lt;CONTAINER NAME&gt;' /* (1)! */ /* (2)! */
directory = ( enable = true);

/* 
    Create a file format so the "copy into"
    command knows how to copy the data.
*/
create or replace file format raw.azure.json
    type = 'json';

-- Create the table to load into.
create or replace table json (
    file_name varchar,
    data variant
);

-- Load the json file from the json folder.
copy into json(file_name,data)
from (
    select 
        metadata$filename,
        $1
    from
        @azure/json
        (file_format =&gt; json)
);
</code></pre></p> <ol> <li> <p></p> </li> <li> <p></p> </li> </ol> <pre><code>use database raw;
